import { PAGE_INFO } from '@/constants/page.constants';
import { logger } from '@/utils/logger';

/**
 * リダイレクト URL を検証して安全な URL のみを許可する
 *
 * Open Redirect 攻撃を防ぐため、以下をチェック：
 * - 相対パスのみ許可（絶対 URL は拒否）
 * - パストラバーサル攻撃の防止
 * - 同一オリジンの確認
 *
 * @param url - 検証する URL（クエリパラメータから取得した値など）
 * @returns 安全な URL。不正な場合はデフォルトパスを返す
 *
 * @example
 * ```typescript
 * // 安全な URL
 * validateRedirectUrl('/dashboard'); // → '/dashboard'
 * validateRedirectUrl('/sessions?tab=active'); // → '/sessions?tab=active'
 *
 * // 危険な URL（外部サイト）
 * validateRedirectUrl('https://evil.com'); // → '/' (デフォルト)
 * validateRedirectUrl('//evil.com'); // → '/' (デフォルト)
 *
 * // パストラバーサル攻撃
 * validateRedirectUrl('/../etc/passwd'); // → '/' (デフォルト)
 * ```
 */
export const validateRedirectUrl = (
  url: string | null | undefined,
): string => {
  // URLが未定義または空の場合はデフォルト
  if (!url || url.trim() === '') {
    return PAGE_INFO.TOP.href();
  }

  // URLデコードして正規化（エンコード攻撃対策）
  let normalizedUrl: string;
  try {
    normalizedUrl = decodeURIComponent(url).toLowerCase();
  } catch {
    // デコードに失敗した場合はそのまま小文字化
    normalizedUrl = url.toLowerCase();
  }

  // 相対パス以外は拒否（プロトコルを含む絶対URLは危険）
  // 攻撃例: https://evil.com, http://evil.com, //evil.com, HtTpS://evil.com, %68%74%74%70://evil.com
  if (
    normalizedUrl.startsWith('http://') ||
    normalizedUrl.startsWith('https://') ||
    normalizedUrl.startsWith('//') ||
    normalizedUrl.startsWith('javascript:') ||
    normalizedUrl.startsWith('data:') ||
    normalizedUrl.startsWith('vbscript:') ||
    normalizedUrl.startsWith('file:')
  ) {
    logger.warn('Security: Rejected absolute URL redirect attempt', { url });
    return PAGE_INFO.TOP.href();
  }

  // 先頭が / でない場合、またはバックスラッシュ始まりは拒否
  // 攻撃例: \evil.com
  // 注意: javascript:, data: などのスキームは上記の normalizedUrl チェックで既に弾かれている
  if (!url.startsWith('/') || url.startsWith('\\')) {
    logger.warn('Security: Rejected non-relative path redirect attempt', {
      url,
    });
    return PAGE_INFO.TOP.href();
  }

  // パストラバーサル攻撃の防止
  // 攻撃例: /../../../etc/passwd, /..\\..\\windows\\system32
  if (url.includes('../') || url.includes('..\\')) {
    logger.warn('Security: Rejected path traversal attempt', { url });
    return PAGE_INFO.TOP.href();
  }

  // 念のため URL オブジェクトで同一オリジン確認
  try {
    const baseUrl =
      typeof window !== 'undefined'
        ? window.location.origin
        : 'http://localhost';
    const parsedUrl = new URL(url, baseUrl);

    // オリジンが一致しない場合は拒否
    if (parsedUrl.origin !== baseUrl) {
      logger.warn('Security: Rejected different origin redirect attempt', {
        url,
        parsedOrigin: parsedUrl.origin,
        expectedOrigin: baseUrl,
      });
      return PAGE_INFO.TOP.href();
    }

    // pathname のみを返す（クエリパラメータとハッシュは保持）
    return parsedUrl.pathname + parsedUrl.search + parsedUrl.hash;
  } catch (error) {
    // URL のパースに失敗した場合はデフォルト
    logger.error('Security: Failed to parse redirect URL', { url, error });
    return PAGE_INFO.TOP.href();
  }
};

/**
 * 現在のパスを安全な callbackUrl として生成する
 *
 * サインインページへのリダイレクト時に使用し、
 * ログイン後に元のページに戻るために使用される
 *
 * @returns エンコードされた現在のパス（pathname + search）
 *
 * @example
 * ```typescript
 * // 現在のURL: https://example.com/sessions?status=active
 * createSafeCallbackUrl(); // → '/sessions?status=active' (エンコード済み)
 * ```
 */
export const createSafeCallbackUrl = (): string => {
  if (typeof window === 'undefined') {
    return encodeURIComponent('/');
  }

  const currentPath = window.location.pathname + window.location.search;

  // パスが不正でないか念のため検証
  if (currentPath.includes('../') || currentPath.includes('..\\')) {
    logger.warn('Security: Invalid path detected in callback URL creation', {
      currentPath,
    });
    return encodeURIComponent('/');
  }

  return encodeURIComponent(currentPath);
};

