              <Button
                sx={{ mt: 4 }}
                type="submit"
                color="success"
                variant="solid"
                size="lg"
                fullWidth
              >{translate('create_new_account')}</Button>
            </Link>
          </Box> */}
        </Stack>
      </form>
    </Box>
  );
}

